//# Pipeline Serial to Parallel Converter

// Reads in multiple serial words (most-significant word first) and signals
// when the last input word has been read-in and a new, wider output word is
// ready to be read-out, in the same cycle if necessary to receive an
// uninterrupted serial stream.

// Holding `clock_enable` low halts any shifting, holding all bits in place
// and ignoring any changes at the control and data inputs, *except for
// `clear`*.

// Asserting `clear` will empty the shift register, re-initialize the counter,
// drop `parallel_out_valid`, and start shifting-in serial words.

// This is a generalization of the simpler [Serial to Parallel Converter](./Serial_Parallel.html).

`default_nettype none

module Pipeline_Serial_Parallel
#(
    parameter WORD_WIDTH_IN     = 0,
    parameter WORD_COUNT_IN     = 0,

    // Do not set at instantiation, except in Vivado IPI
    parameter WORD_WIDTH_OUT    = WORD_WIDTH_IN * WORD_COUNT_IN
)
(
    input   wire                            clock,
    input   wire                            clock_enable,
    input   wire                            clear,

    input   wire                            serial_in_valid,
    output  reg                             serial_in_ready,
    input   wire    [WORD_WIDTH_IN-1:0]     serial_in,

    output  reg                             parallel_out_valid,
    input   wire                            parallel_out_ready,
    output  wire    [WORD_WIDTH_OUT-1:0]    parallel_out
);

    `include "clog2_function.vh"

    localparam WORD_ZERO_IN     = {WORD_WIDTH_IN{1'b0}};
    localparam WORD_ZERO_OUT    = {WORD_COUNT_IN{WORD_ZERO_IN}};
    localparam COUNT_WIDTH      = clog2(WORD_COUNT_IN) + 1;   // Since we must be able to index 0 to N, not N-1
    localparam COUNT_ZERO       = {COUNT_WIDTH{1'b0}};

    initial begin
        parallel_out_valid  = 1'b0; // We start empty, so ready to shift-in.
        serial_in_ready     = 1'b1;
    end

// Count the number of word shifts remaining. When the last word has been
// read-in from `serial_in`, the count reaches zero, the counter halts, and we
// can immediately read out the word.

// As the initial output word is read out, we reload the counter with the
// initial value if there is no concurrent serial input, or with one less than
// the initial value if there is a concurrent serial input.

    reg                     counter_run         = 1'b0;
    reg                     counter_load        = 1'b0;
    reg  [COUNT_WIDTH-1:0]  counter_load_value  = COUNT_ZERO;
    wire [COUNT_WIDTH-1:0]  count;

    Counter_Binary
    #(
        .WORD_WIDTH     (COUNT_WIDTH),
        .INCREMENT      (1),
        .INITIAL_COUNT  (WORD_COUNT_IN [COUNT_WIDTH-1:0])
    )
    shifts_remaining
    (
        .clock          (clock),
        .clear          (clear),
        .up_down        (1'b1), // 0 up, 1 down
        .run            (counter_run),
        .load           (counter_load),
        .load_count     (counter_load_value [COUNT_WIDTH-1:0]),
        .carry_in       (1'b0),
        // verilator lint_off PINCONNECTEMPTY
        .carry_out      (),
        .carries        (),
        .overflow       (),
        // verilator lint_on  PINCONNECTEMPTY
        .count          (count)
    );

// The shift register only shifts when the counter is running.

    reg shifter_run  = 1'b0;

    Register_Pipeline
    #(
        .WORD_WIDTH     (WORD_WIDTH_IN),
        .PIPE_DEPTH     (WORD_COUNT_IN),
        .RESET_VALUES   (WORD_ZERO_OUT)
    )
    shift_register
    (
        .clock          (clock),
        .clock_enable   (shifter_run),
        .clear          (clear),
        .parallel_load  (1'b0),
        .parallel_in    (WORD_ZERO_OUT),
        .parallel_out   (parallel_out),
        .pipe_in        (serial_in),
        // verilator lint_off PINCONNECTEMPTY
        .pipe_out       ()
        // verilator lint_on  PINCONNECTEMPTY
    );

// Completing the parallel output handshake reloads the counter, starting the
// word shifting.  After all the words have been read-in from `serial_in`, the
// counter reaches to zero, halts, and raises `parallel_out_valid`.

    reg output_handshake_done   = 1'b0;
    reg input_handshake_done    = 1'b0;

    always @(*) begin
        output_handshake_done   = (parallel_out_valid == 1'b1) && (parallel_out_ready == 1'b1);
        input_handshake_done    = (serial_in_valid    == 1'b1) && (serial_in_ready    == 1'b1);
    end

    always @(*) begin
        parallel_out_valid      =  (count == COUNT_ZERO)                                     && (clock_enable == 1'b1);
        serial_in_ready         = ((count != COUNT_ZERO) || (output_handshake_done == 1'b1)) && (clock_enable == 1'b1);

        counter_run             =  (count != COUNT_ZERO) && (input_handshake_done  == 1'b1)  && (clock_enable == 1'b1);
        counter_load            = (output_handshake_done == 1'b1);

        shifter_run             = (counter_run == 1'b1) || (counter_load == 1'b1);

        counter_load_value      = ((output_handshake_done == 1'b1) && (input_handshake_done == 1'b1)) ? WORD_COUNT_IN - 1 : WORD_COUNT_IN;
    end

endmodule

//# Parallel to Serial Converter

// Reads in a data word, sends it out serially, bit by bit (MSB first), and
// signals when the final bit is out and a new data word can be read-in, in
// the same cycle if necessary to create an uninterrupted serial stream.

// When the `parallel_in` ready/valid handshakes completes, `parallel_in` is
// loaded, `parallel_in_ready` goes low while the bits shift out (MSB first),
// and goes back high once the last loaded bit appears at `serial_out`,
// allowing a simultanous reload for a continuous stream of serial bits to be
// sent.

// Otherwise, if no new word is loaded, the shifter halts (holding the last
// bit steady at `serial_out`, and `parallel_in_ready` goes high, awaiting the
// next load.

// Holding `clock_enable` low halts any shifting, holding all bits in place
// and ignoring any changes at the control and data inputs, *except for
// `clear`*.

// Asserting `clear` will empty the shift register, zero-out the counter,
// raise `parallel_in_ready`, and halt all activity until the next ready/valid
// handshake.

`default_nettype none

module Parallel_Serial
#(
    parameter WORD_WIDTH = 0
)
(
    input   wire                        clock,
    input   wire                        clock_enable,
    input   wire                        clear,

    input   wire                        parallel_in_valid,
    output  reg                         parallel_in_ready,
    input   wire    [WORD_WIDTH-1:0]    parallel_in,

    output  wire                        serial_out
);

    `include "clog2_function.vh"

    localparam WORD_ZERO   = {WORD_WIDTH{1'b0}};
    localparam COUNT_WIDTH = clog2(WORD_WIDTH);
    localparam COUNT_ZERO  = {COUNT_WIDTH{1'b0}};
    localparam COUNT_BITS  = WORD_WIDTH - 1; 

    initial begin
        parallel_in_ready = 1'b1; // We start empty, so ready to load.
    end

// Count the number of bit shifts remaning, starting at WORD_WIDTH-1 since the
// first bit is immediately visible at `serial_out` after a load.  When the
// last bit is visible at `serial_out`, the count reaches zero, the counter
// halts, and we can immediately load a new word.

    reg                     counter_run  = 1'b0;
    reg                     counter_load = 1'b0;
    wire [COUNT_WIDTH-1:0]  count;

    Counter_Binary
    #(
        .WORD_WIDTH     (COUNT_WIDTH),
        .INCREMENT      (1),
        .INITIAL_COUNT  (COUNT_ZERO)
    )
    shifts_remaining
    (
        .clock          (clock),
        .clear          (clear),
        .up_down        (1'b1), // 0 up, 1 down
        .run            (counter_run),
        .load           (counter_load),
        .load_count     (COUNT_BITS [COUNT_WIDTH-1:0]),
        .carry_in       (1'b0),
        // verilator lint_off PINCONNECTEMPTY
        .carry_out      (),
        .carries        (),
        .overflow       (),
        // verilator lint_on  PINCONNECTEMPTY
        .count          (count)
    );

// The shift register only shifts when the counter is running.

    reg shifter_run  = 1'b0;
    reg shifter_load = 1'b0;

    Register_Pipeline
    #(
        .WORD_WIDTH     (1),
        .PIPE_DEPTH     (WORD_WIDTH),
        .RESET_VALUES   (WORD_ZERO)
    )
    shift_register
    (
        .clock          (clock),
        .clock_enable   (shifter_run),
        .clear          (clear),
        .parallel_load  (shifter_load),
        .parallel_in    (parallel_in),
        // verilator lint_off PINCONNECTEMPTY
        .parallel_out   (),
        // verilator lint_on  PINCONNECTEMPTY
        .pipe_in        (1'b0),
        .pipe_out       (serial_out)
    );

// Completing the parallel input handshake both loads the data word into the
// shift register and loads the counter with the pipeline depth (minus 1),
// starting the bit shifting.  After all the bits have appeared at
// `serial_out`, the counter reaches to zero, halts, and raises
// `parallel_in_ready`.

    reg handshake_done = 1'b0;

    always @(*) begin
        parallel_in_ready   = (count == COUNT_ZERO) && (clock_enable == 1'b1);
        handshake_done      = (parallel_in_valid == 1'b1) && (parallel_in_ready == 1'b1);

        counter_run         = (count != COUNT_ZERO) && (clock_enable == 1'b1);
        counter_load        = (handshake_done == 1'b1);

        shifter_run         = (counter_run == 1'b1) || (counter_load == 1'b1);
        shifter_load        = (counter_load == 1'b1);
    end

endmodule

//# IDELAYCTRL: A controller for IDELAY2 blocks

// **This module is specific to Series 7 AMD/Xilinx FPGA devices.**
// Instantiates an IDELAYCTRL block for automatically calibrating the delay
// line in the IDELAY2 programmable delay blocks in an I/O Bank.  IDELAY2s are
// typically used with high-speed interfaces where the delay across multiple
// I/O pins must be fine-tuned to match in the sub-nanosecond range.

// This is a trivial wrapper module, but it does convert a Verilog attribute
// on the module instance into a parameter, which makes for a cleaner
// composition into larger designs.

//## Usage

// One IDELAYCTRL is needed per I/O Bank and the controlled IDELAY2 blocks
// must be in the same `IODELAY_GROUP`.  If `ready` drops then calibration was
// lost, likely due to a `reference_clock` glitch: reset and retrain your
// interface logic.  See the "*7 Series FPGAs SelectIO Resources User Guide
// (UG471)*" for details on the allowable reference clock frequency ranges.

`default_nettype none

module IDELAYCTRL_Instance
#(
    parameter IODELAY_GROUP     = ""    // Must match with the IDELAY2 blocks
)
(
    input  wire                 reference_clock,    // See UG471 for allowable frequency ranges
    input  wire                 reset,
    output wire                 ready               // If this drops, reset and retrain
);


    (* IODELAY_GROUP = IODELAY_GROUP *) // Specifies group name for associated IDELAY2s/ODELAY2s and IDELAYCTRL

    IDELAYCTRL 
    idelay2_control (
        .RDY    (ready),            // 1-bit output: Ready output
        .REFCLK (reference_clock),  // 1-bit input:  Reference clock input
        .RST    (reset)             // 1-bit input:  Active high reset input
    );

endmodule

//# Differential Input Deserializer with 1 to N Ratio

// Takes in a serial differential data stream, at single or double data rate,
// and deserialises it as parallel words of both positive and negative
// polarity.  The input delays on the negative and positive signal polarity
// can be individually adjusted for bit-alignment training, and the hardware
// can bitslip for word-alignment training. All training is done by external
// modules.

// As an example, a DDR data stream at a `clk_serial` of 300 MHz with
// a `clk_parallel` of 100 MHz implies a `DATA_WIDTH` of 6, and thus a ratio
// of 1:6.

//## Usage Notes

// **This module is specific to Series 7 AMD/Xilinx FPGAs.** Please refer to
// the "*7 Series FPGAs SelectIO Resources User Guide (UG471)*" for details.
// However, the architecture is the same for many other FPGAs, so you can
// alter this design to fit your needs. 

// All the `IDELAYE2` modules in an I/O Bank depend on one instance of the 
// [IDELAYCTRL](./IDELAYCTRL_Instance.html) 
// module to maintain delay calibration and both
// must know the `IODELAY_REFCLK_FREQUENCY` delay reference clock frequency.

// **NOTE: If you change `DATA_WIDTH`, then you must manually rewire the
// `datain_p_parallel` and `datain_n_parallel` outputs at the ISERDESE2
// module.** This is cleaner than trying to automate it, and will avoid
// generating warnings about unused wires.

// The serial data is in the `clk_serial` domain. All other control and data
// signals are in the `clk_parallel` domain.

//## Parameters and Ports

`default_nettype none

module Deserializer_Differential_1toN
#(
    // For the input buffer of each data line

    parameter IBUF_DIFF_TERM                = "",               // Differential Termination, "TRUE"/"FALSE" 
    parameter IBUF_LOW_PWR                  = "",               // Low power="TRUE", Highest performance="FALSE" 
    parameter IBUF_IOSTANDARD               = "",               // Specify the input I/O standard (e.g.: "LVDS_25")

    parameter IODELAY_REFCLK_FREQUENCY      = ""                // External IDELAYCTRL reference clock input frequency in MHz (190.0-210.0, 290.0-310.0) 
    parameter IODELAY_GROUP                 = "",               // Must match IODELAY_GROUP applied to IDELAYCTRL module in same I/O Bank.
    parameter IODELAY_HIGH_PERFORMANCE_MODE = "",               // Reduced jitter ("TRUE"), Reduced power ("FALSE"). The clock source should have the same setting.

    // For the SERDES hardware

    parameter DATA_RATE                     = "",               // "DDR" or "SDR".
    parameter DATA_WIDTH                    = 6,                // How many bits to deserialize into? Must be natively supported by SERDES hardware. (UPDATE PARALLEL DATA WIRING AT SERDES!)

    // Do not set at instantiation, except in Vivado IPI

    parameter TAP_COUNTER_WIDTH             = 5                // Hardcoded to match the IDELAY2 hardware. See UG471.
)
(
    input  wire                             clk_serial,         // High-speed I/O clock for incoming serial data (IO only)
    input  wire                             clk_parallel,       // "Low-speed" clock for outgoing parallel data and all control inputs
    input  wire                             reset_parallel,     // Asynchronous/Synchronous reset in clk_parallel domain

    input  wire                             datain_n,           // High-speed serial I/O data in
    input  wire                             datain_p,

    // Positive input delay and bitslip control

    input  wire                             incdec_p_enable,    // Enable increment/decrement of delay tap
    input  wire                             incdec_p,           // Increment (1) or decrement (0) delay tap 
    output wire     [TAP_COUNTER_WIDTH-1:0] tap_p_current,      // Current value of delay tap
    input  wire     [TAP_COUNTER_WIDTH-1:0] tap_p_load_value,   // New value of delay tap
    input  wire                             tap_p_load,         // Load new delay tap value
    input  wire                             datain_p_bitslip,   // Pulse to shift output word
    output wire     [DATA_WIDTH-1:0]        datain_p_parallel,  // Deserialized data in clk_parallel domain

    // Negative input delay and bitslip control

    input  wire                             incdec_n_enable,    // Enable increment/decrement of delay tap
    input  wire                             incdec_n,           // Increment (1) or decrement (0) delay tap 
    output wire     [TAP_COUNTER_WIDTH-1:0] tap_n_current,      // Current value of delay tap
    input  wire     [TAP_COUNTER_WIDTH-1:0] tap_n_load_value,   // New value of delay tap
    input  wire                             tap_n_load,         // Load new delay tap value
    input  wire                             datain_n_bitslip,   // Pulse to shift output word
    output wire     [DATA_WIDTH-1:0]        datain_n_parallel   // Deserialized data in clk_parallel domain
);

//## Input Buffering

// First, buffer the differential input using a buffer with differential
// outputs. Each output polarity will go through its own delay and
// deserializer.

    wire datain_p_buffered;
    wire datain_n_buffered;

    IBUFDS_DIFF_OUT
    #(
        .DIFF_TERM    (IBUF_DIFF_TERM), // Differential Termination, "TRUE"/"FALSE" 
        .IBUF_LOW_PWR (IBUF_LOW_PWR),   // Low power="TRUE", Highest performance="FALSE" 
        .IOSTANDARD   (IBUF_IOSTANDARD) // Specify the input I/O standard
    )
    diff_input_buffer
    (
        .I            (datain_p),             // Diff_p buffer input (connect directly to top-level port)
        .IB           (datain_n),             // Diff_n buffer input (connect directly to top-level port)
        .O            (datain_p_buffered),    // Buffer diff_p output
        .OB           (datain_n_buffered)     // Buffer diff_n output
    );

//## Input Delays

// Instantiate an input delay for the data. An external module will adjust the
// delay taps to centre the data bit inside the clock (bit-alignment). 

// All the `IDELAY2` blocks inside an I/O Bank *must* be associated with
// exactly one `IDELAYCTRL` block per I/O Bank by sharing the same
// `IODELAY_GROUP` attribute.

//### Input Delay (Positive)

    wire datain_p_delayed;

    (* IODELAY_GROUP = IODELAY_GROUP *) // Specifies group name for associated IDELAY2s/ODELAY2s and IDELAYCTRL

    IDELAYE2
    #(
        .CINVCTRL_SEL           ("FALSE"),                      // Enable dynamic clock inversion (FALSE, TRUE)
        .DELAY_SRC              ("IDATAIN"),                    // Delay input (IDATAIN, DATAIN)
        .HIGH_PERFORMANCE_MODE  (IODELAY_HIGH_PERFORMANCE_MODE), // Reduced jitter ("TRUE"), Reduced power ("FALSE")
        .IDELAY_TYPE            ("VAR_LOAD"),                   // FIXED, VARIABLE, VAR_LOAD, VAR_LOAD_PIPE
        .IDELAY_VALUE           (0),                            // Input delay tap setting (0-31)
        .PIPE_SEL               ("FALSE"),                      // Select pipelined mode, FALSE, TRUE
        .REFCLK_FREQUENCY       (IODELAY_REFCLK_FREQUENCY),     // IDELAYCTRL clock input frequency in MHz (190.0-210.0, 290.0-310.0).
        .SIGNAL_PATTERN         ("DATA")                        // DATA, CLOCK input signal
    )
    input_data_delay_p 
    (
        .CNTVALUEOUT            (tap_p_current),        // 5-bit output: Counter value output
        .DATAOUT                (datain_p_delayed),     // 1-bit output: Delayed data output
        .C                      (clk_parallel),         // 1-bit input: Clock input
        .CE                     (incdec_p_enable),      // 1-bit input: Active high enable increment/decrement input
        .CINVCTRL               (1'b0),                 // 1-bit input: Dynamic clock inversion input
        .CNTVALUEIN             (tap_p_load_value),     // 5-bit input: Counter value input
        .DATAIN                 (1'b0),                 // 1-bit input: Internal delay data input
        .IDATAIN                (datain_p_buffered),    // 1-bit input: Data input from the I/O
        .INC                    (incdec_p),             // 1-bit input: Increment / Decrement tap delay input
        .LD                     (tap_p_load),           // 1-bit input: Load IDELAY_VALUE input
        .LDPIPEEN               (1'b0),                 // 1-bit input: Enable PIPELINE register to load data input
        .REGRST                 (reset_parallel)        // 1-bit input: Active-high reset tap-delay input
    );

//### Input Delay (Negative)

    wire datain_n_delayed;

    (* IODELAY_GROUP = IODELAY_GROUP *) // Specifies group name for associated IDELAYs/ODELAYs and IDELAYCTRL

    IDELAYE2
    #(
        .CINVCTRL_SEL           ("FALSE"),                      // Enable dynamic clock inversion (FALSE, TRUE)
        .DELAY_SRC              ("IDATAIN"),                    // Delay input (IDATAIN, DATAIN)
        .HIGH_PERFORMANCE_MODE  (IODELAY_HIGH_PERFORMANCE_MODE), // Reduced jitter ("TRUE"), Reduced power ("FALSE")
        .IDELAY_TYPE            ("VAR_LOAD"),                   // FIXED, VARIABLE, VAR_LOAD, VAR_LOAD_PIPE
        .IDELAY_VALUE           (0),                            // Input delay tap setting (0-31)
        .PIPE_SEL               ("FALSE"),                      // Select pipelined mode, FALSE, TRUE
        .REFCLK_FREQUENCY       (IODELAY_REFCLK_FREQUENCY),     // IDELAYCTRL clock input frequency in MHz (190.0-210.0, 290.0-310.0).
        .SIGNAL_PATTERN         ("DATA")                        // DATA, CLOCK input signal
    )
    input_data_delay_n 
    (
        .CNTVALUEOUT            (tap_n_current),        // 5-bit output: Counter value output
        .DATAOUT                (datain_n_delayed),     // 1-bit output: Delayed data output
        .C                      (clk_parallel),         // 1-bit input: Clock input
        .CE                     (incdec_n_enable),      // 1-bit input: Active high enable increment/decrement input
        .CINVCTRL               (1'b0),                 // 1-bit input: Dynamic clock inversion input
        .CNTVALUEIN             (tap_n_load_value),     // 5-bit input: Counter value input
        .DATAIN                 (1'b0),                 // 1-bit input: Internal delay data input
        .IDATAIN                (datain_n_buffered),    // 1-bit input: Data input from the I/O
        .INC                    (incdec_n),             // 1-bit input: Increment / Decrement tap delay input
        .LD                     (tap_n_load),           // 1-bit input: Load IDELAY_VALUE input
        .LDPIPEEN               (1'b0),                 // 1-bit input: Enable PIPELINE register to load data input
        .REGRST                 (reset_parallel)        // 1-bit input: Active-high reset tap-delay input
    );

//## Input Deserializations

// Now, independently deserialize the positive and negative data. The
// `DATA_WIDTH` must be natively supported by the `ISERDESE2` block.

// **NOTE:** The parallel data is deserialized in bit-reverse order, so we
// wire up the `datain_p_parallel` outputs in reverse to compensate. **Also,
// if you alter the `DATA_WIDTH`, then you must manually adjust the wiring
// here.** This is clearer than trying to make some clever automatic re-wiring
// that would create warnings about unused wires, and is not something that
// changes in a design anyway.

//### Input Deserialization (Positive)

    ISERDESE2
    #(
        .DATA_RATE          (DATA_RATE),    // "DDR", "SDR"
        .DATA_WIDTH         (DATA_WIDTH),   // Parallel data width (2-8,10,14)
        .DYN_CLKDIV_INV_EN  ("FALSE"),      // Enable DYNCLKDIVINVSEL inversion (FALSE, TRUE)
        .DYN_CLK_INV_EN     ("FALSE"),      // Enable DYNCLKINVSEL inversion (FALSE, TRUE)
        // INIT_Q1 - INIT_Q4: Initial value on the Q outputs (0/1)
        .INIT_Q1            (1'b0),
        .INIT_Q2            (1'b0),
        .INIT_Q3            (1'b0),
        .INIT_Q4            (1'b0),
        .INTERFACE_TYPE     ("NETWORKING"), // MEMORY, MEMORY_DDR3, MEMORY_QDR, NETWORKING, OVERSAMPLE
        .IOBDELAY           ("BOTH"),       // NONE, BOTH, IBUF, IFD
        .NUM_CE             (1),            // Number of clock enables (1,2)
        .OFB_USED           ("FALSE"),      // Select OFB path (FALSE, TRUE)
        .SERDES_MODE        ("MASTER"),     // MASTER, SLAVE
        // SRVAL_Q1 - SRVAL_Q4: Q output values when SR is used (0/1)
        .SRVAL_Q1           (1'b0),
        .SRVAL_Q2           (1'b0),
        .SRVAL_Q3           (1'b0),
        .SRVAL_Q4           (1'b0)
    )
    input_data_serdes_p
    (
        // verilator lint_off PINCONNECTEMPTY
        .O                  (),             // 1-bit output: Combinatorial output
        // Q1 - Q8: 1-bit (each) output: Registered data outputs.
        // *** BIT-REVERSED ORDER! ***
        .Q1                 (datain_p_parallel[5]),     // Example wiring for DATA_WIDTH = 6.
        .Q2                 (datain_p_parallel[4]),
        .Q3                 (datain_p_parallel[3]),
        .Q4                 (datain_p_parallel[2]),
        .Q5                 (datain_p_parallel[1]),
        .Q6                 (datain_p_parallel[0]),
        .Q7                 (),
        .Q8                 (),
        // SHIFTOUT1, SHIFTOUT2: 1-bit (each) output: Data width expansion output ports
        .SHIFTOUT1          (),
        .SHIFTOUT2          (),
        // verilator lint_on PINCONNECTEMPTY
        // 1-bit input: The BITSLIP pin performs a Bitslip operation
        // synchronous to CLKDIV when asserted (active High). Subsequently,
        // the data seen on the Q1 to Q8 output ports will shift one position
        // every time Bitslip is invoked (DDR operation is different from SDR).
        .BITSLIP            (datain_p_bitslip),
        // CE1, CE2: 1-bit (each) input: Data register clock enable inputs
        .CE1                (1'b1),
        .CE2                (1'b1),
        .CLKDIVP            (1'b0),             // 1-bit input: TBD
        // Clocks: 1-bit (each) input: ISERDESE2 clock input ports
        .CLK                (clk_serial),       // 1-bit input: High-speed clock
        .CLKB               (~clk_serial),      // 1-bit input: High-speed secondary clock
        .CLKDIV             (clk_parallel),     // 1-bit input: Divided clock
        .OCLK               (1'b0),             // 1-bit input: High speed output clock used when INTERFACE_TYPE="MEMORY" 
        // Dynamic Clock Inversions: 1-bit (each) input: Dynamic clock inversion pins to switch clock polarity
        .DYNCLKDIVSEL       (1'b0),             // 1-bit input: Dynamic CLKDIV inversion
        .DYNCLKSEL          (1'b0),             // 1-bit input: Dynamic CLK/CLKB inversion
        // Input Data: 1-bit (each) input: ISERDESE2 data input ports
        .D                  (1'b0),             // 1-bit input: Data input
        .DDLY               (datain_p_delayed), // 1-bit input: Serial data from IDELAYE2
        .OFB                (1'b0),             // 1-bit input: Data feedback from OSERDESE2
        .OCLKB              (1'b0),             // 1-bit input: High speed negative edge output clock
        .RST                (reset_parallel),   // 1-bit input: Active high asynchronous reset
        // SHIFTIN1, SHIFTIN2: 1-bit (each) input: Data width expansion input ports
        .SHIFTIN1           (1'b0),
        .SHIFTIN2           (1'b0)
    );

//### Input Deserialization (Negative)

    ISERDESE2
    #(
        .DATA_RATE          (DATA_RATE),    // "DDR", "SDR"
        .DATA_WIDTH         (DATA_WIDTH),   // Parallel data width (2-8,10,14)
        .DYN_CLKDIV_INV_EN  ("FALSE"),      // Enable DYNCLKDIVINVSEL inversion (FALSE, TRUE)
        .DYN_CLK_INV_EN     ("FALSE"),      // Enable DYNCLKINVSEL inversion (FALSE, TRUE)
        // INIT_Q1 - INIT_Q4: Initial value on the Q outputs (0/1)
        .INIT_Q1            (1'b0),
        .INIT_Q2            (1'b0),
        .INIT_Q3            (1'b0),
        .INIT_Q4            (1'b0),
        .INTERFACE_TYPE     ("NETWORKING"), // MEMORY, MEMORY_DDR3, MEMORY_QDR, NETWORKING, OVERSAMPLE
        .IOBDELAY           ("BOTH"),       // NONE, BOTH, IBUF, IFD
        .NUM_CE             (1),            // Number of clock enables (1,2)
        .OFB_USED           ("FALSE"),      // Select OFB path (FALSE, TRUE)
        .SERDES_MODE        ("MASTER"),     // MASTER, SLAVE
        // SRVAL_Q1 - SRVAL_Q4: Q output values when SR is used (0/1)
        .SRVAL_Q1           (1'b0),
        .SRVAL_Q2           (1'b0),
        .SRVAL_Q3           (1'b0),
        .SRVAL_Q4           (1'b0)
    )
    input_data_serdes_n
    (
        // verilator lint_off PINCONNECTEMPTY
        .O                  (),             // 1-bit output: Combinatorial output
        // Q1 - Q8: 1-bit (each) output: Registered data outputs
        // *** BIT-REVERSED ORDER! ***
        .Q1                 (datain_n_parallel[5]),     // Example wiring for DATA_WIDTH = 6  
        .Q2                 (datain_n_parallel[4]),
        .Q3                 (datain_n_parallel[3]),
        .Q4                 (datain_n_parallel[2]),
        .Q5                 (datain_n_parallel[1]),
        .Q6                 (datain_n_parallel[0]),
        .Q7                 (),
        .Q8                 (),
        // SHIFTOUT1, SHIFTOUT2: 1-bit (each) output: Data width expansion output ports
        .SHIFTOUT1          (),
        .SHIFTOUT2          (),
        // verilator lint_on PINCONNECTEMPTY
        // 1-bit input: The BITSLIP pin performs a Bitslip operation
        // synchronous to CLKDIV when asserted (active High). Subsequently,
        // the data seen on the Q1 to Q8 output ports will shift one position
        // every time Bitslip is invoked (DDR operation is different from SDR).
        .BITSLIP            (datain_n_bitslip),
        // CE1, CE2: 1-bit (each) input: Data register clock enable inputs
        .CE1                (1'b1),
        .CE2                (1'b1),
        .CLKDIVP            (1'b0),             // 1-bit input: TBD
        // Clocks: 1-bit (each) input: ISERDESE2 clock input ports
        .CLK                (clk_serial),       // 1-bit input: High-speed clock
        .CLKB               (~clk_serial),      // 1-bit input: High-speed secondary clock
        .CLKDIV             (clk_parallel),     // 1-bit input: Divided clock
        .OCLK               (1'b0),             // 1-bit input: High speed output clock used when INTERFACE_TYPE="MEMORY" 
        // Dynamic Clock Inversions: 1-bit (each) input: Dynamic clock inversion pins to switch clock polarity
        .DYNCLKDIVSEL       (1'b0),             // 1-bit input: Dynamic CLKDIV inversion
        .DYNCLKSEL          (1'b0),             // 1-bit input: Dynamic CLK/CLKB inversion
        // Input Data: 1-bit (each) input: ISERDESE2 data input ports
        .D                  (1'b0),             // 1-bit input: Data input
        .DDLY               (datain_n_delayed), // 1-bit input: Serial data from IDELAYE2
        .OFB                (1'b0),             // 1-bit input: Data feedback from OSERDESE2
        .OCLKB              (1'b0),             // 1-bit input: High speed negative edge output clock
        .RST                (reset_parallel),   // 1-bit input: Active high asynchronous reset
        // SHIFTIN1, SHIFTIN2: 1-bit (each) input: Data width expansion input ports
        .SHIFTIN1           (1'b0),
        .SHIFTIN2           (1'b0)
    );

endmodule

//# Register Pipeline

// Pipelines data words through a number of register stages, with both
// parallel and serial inputs and outputs. Besides the obvious uses for
// serial/parallel conversion and pipeline alignment, a register pipeline can
// be part of shift-and-add algorithms such as multiplication through
// conditional addition.

// Each cycle `clock_enable` is high, the pipeline shifts by one from LSB to
// MSB, or loads a new set of parallel values. **Load overrides shift**.
// `pipe_in` feeds the LSB, and `pipe_out` read from the MSB.

// **NOTE**: `PIPE_DEPTH` must be 1 or greater.  (*Supporting a depth of zero
// would make this code far too messy and leave the parallel input/output
// ports unconnected, which will raise CAD warnings. See the [Simple Register
// Pipeline](./Register_Pipeline_Simple.html) instead.*)

// Depending on how you parameterize and use it, a register pipeline can act
// as a delay pipeline or a shift register:

// * For a delay pipeline, set `WORD_WIDTH` to the width of the data word, then
// `PIPE_DEPTH` to the number of delay stages. This will move whole data words
// along the pipeline. 
// * For a shift register, set `WORD_WIDTH` to 1, and `PIPE_DEPTH` to the
// width of the data word you wish to shift in or out bit-by-bit. Load the
// word via `parallel_in`, then shift it out through `pipe_out`. Or, shift in
// `PIPE_DEPTH` bits through `pipe_in`, then read the data word on
// `parallel_out`.

// If no parallel loads are required, hardwire `parallel_load` to zero, and
// the multiplexers will optimize away, if any, and you'll end up with a pure
// shift register (but see the [Simple Register
// Pipeline](./Register_Pipeline_Simple.html) if this is your main use-case).
// Conversely, hardwire `parallel_load` to one, and tie off the `pipe_in`
// input, and you'll end up with a conveniently packaged bank of registers.

// The `RESET_VALUES` parameter allows each pipeline stage to start loaded
// with a known initial value, which can simplify system startup. The pipeline
// will also clear to the same values. Set `RESET_VALUES` to the concatenation
// of all initial/reset values, with the rightmost value being the first one
// (at the least-significant bit (LSB)).


`default_nettype none

module Register_Pipeline
#(
    parameter                   WORD_WIDTH      = 0,
    parameter                   PIPE_DEPTH      = 0,
    // Don't set at instantiation
    parameter                   TOTAL_WIDTH     = WORD_WIDTH * PIPE_DEPTH,

    // concatenation of each stage initial/reset value
    parameter [TOTAL_WIDTH-1:0] RESET_VALUES    = 0
)
(
    input   wire                        clock,
    input   wire                        clock_enable,
    input   wire                        clear,
    input   wire                        parallel_load,
    input   wire    [TOTAL_WIDTH-1:0]   parallel_in,
    output  reg     [TOTAL_WIDTH-1:0]   parallel_out,
    input   wire    [WORD_WIDTH-1:0]    pipe_in,
    output  reg     [WORD_WIDTH-1:0]    pipe_out
);

    localparam WORD_ZERO = {WORD_WIDTH{1'b0}};

    initial begin
        pipe_out = WORD_ZERO;
    end

// Each pipeline state is composed of a Multiplexer feeding a Register, so we
// can select either the output of the previous Register, or the parallel load
// data. So we need a set of input and ouput wires for each stage. 

    wire [WORD_WIDTH-1:0] pipe_stage_in     [PIPE_DEPTH-1:0];
    wire [WORD_WIDTH-1:0] pipe_stage_out    [PIPE_DEPTH-1:0];

// The following attributes prevent the implementation of the multiplexer with
// DSP blocks. This can be a useful implementation choice sometimes, but here
// it's terrible, since FPGA flip-flops usually have separate data and
// synchronous load inputs, giving us a 2:1 mux for free. If not, then we
// should use LUTs instead, or other multiplexers built into the logic blocks.

    (* multstyle = "logic" *) // Quartus
    (* use_dsp   = "no" *)    // Vivado

// We strip out first iteration of module instantiations to avoid having to
// refer to index -1 in the generate loop, and also to connect to `pipe_in`
// rather than the output of a previous register.

    Multiplexer_Binary_Behavioural
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .ADDR_WIDTH     (1),
        .INPUT_COUNT    (2)
    )
    pipe_input_select
    (
        .selector       (parallel_load),    
        .words_in       ({parallel_in[0 +: WORD_WIDTH], pipe_in}),
        .word_out       (pipe_stage_in[0])
    );

    Register
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .RESET_VALUE    (RESET_VALUES[0 +: WORD_WIDTH])
    )
    pipe_stage
    (
        .clock          (clock),
        .clock_enable   (clock_enable),
        .clear          (clear),
        .data_in        (pipe_stage_in[0]),
        .data_out       (pipe_stage_out[0])
    );

    always @(*) begin
        parallel_out[0 +: WORD_WIDTH] = pipe_stage_out[0];
    end

// Now repeat over the remainder of the pipeline stages, starting at stage 1,
// connecting each pipeline stage to the output of the previous pipeline
// stage.

    generate

        genvar i;

        for(i=1; i < PIPE_DEPTH; i=i+1) begin : pipe_stages

            (* multstyle = "logic" *) // Quartus
            (* use_dsp   = "no" *)    // Vivado

            Multiplexer_Binary_Behavioural
            #(
                .WORD_WIDTH     (WORD_WIDTH),
                .ADDR_WIDTH     (1),
                .INPUT_COUNT    (2)
            )
            pipe_input_select
            (
                .selector       (parallel_load),    
                .words_in       ({parallel_in[WORD_WIDTH*i +: WORD_WIDTH], pipe_stage_out[i-1]}),
                .word_out       (pipe_stage_in[i])
            );


            Register
            #(
                .WORD_WIDTH     (WORD_WIDTH),
                .RESET_VALUE    (RESET_VALUES[WORD_WIDTH*i +: WORD_WIDTH])
            )
            pipe_stage
            (
                .clock          (clock),
                .clock_enable   (clock_enable),
                .clear          (clear),
                .data_in        (pipe_stage_in[i]),
                .data_out       (pipe_stage_out[i])
            );

            always @(*) begin
                parallel_out[WORD_WIDTH*i +: WORD_WIDTH] = pipe_stage_out[i];
            end

        end

    endgenerate

// And finally, connect the output of the last register to the module pipe output.

    always @(*) begin
        pipe_out = pipe_stage_out[PIPE_DEPTH-1];
    end

endmodule
